        <tr style="border-top:2px solid #7b4a2d;"><td style="padding:10px 0;font-weight:700;color:#7b4a2d;font-size:15px;">Total</td><td style="padding:10px 0;text-align:right;font-weight:700;color:#7b4a2d;font-size:15px;">${Number(e.total).toFixed(3)} BHD</td></tr>
